export async function claimNext(db: { query(sql: string): Promise<unknown> }) {
  return db.query("UPDATE tasks SET status = 'running' WHERE id = (SELECT id FROM tasks WHERE status = 'pending' LIMIT 1 FOR UPDATE SKIP LOCKED)");
}

